const uart=@import("../console/uart.zig"); const vm=@import("vm.zig"); const vcpu=@import("vcpu.zig"); const hgatp=@import("hgatp_candidate.zig"); const sp=@import("stage2_activation_plan.zig"); const gef=@import("guest_entry_frame.zig"); const trf=@import("trap_return_frame.zig");
pub const State=enum{empty,built,validated,rejected}; pub const Blocker=enum{none,empty,hgatp_missing,activation_plan_missing,entry_frame_missing,trap_return_frame_missing,guest_entered_forbidden,instruction_executed_forbidden,trap_return_executed_forbidden,hgatp_written_forbidden,active_stage2_forbidden,checksum_zero}; pub const Next=enum{none,build_hgatp_candidate,build_activation_plan,build_guest_entry_frame,build_trap_return_frame,guarded_trap_return_assembly_preparation}; pub const Result=enum{ok,rejected};
pub const Dependency=struct{name:[]const u8,present:bool,valid:bool,checksum:usize,blocker:Blocker}; pub const FirstInstructionReadinessPlan=struct{owner_vm_id:vm.VmId,owner_vcpu_id:vcpu.VcpuId,state:State,deps:[4]Dependency,first_blocker:Blocker,blocker_count:usize,next_required_action:Next,execution_chain_checksum:usize,consumed_hgatp_checksum:usize,consumed_activation_plan_checksum:usize,consumed_guest_entry_frame_checksum:usize,consumed_trap_return_frame_checksum:usize,build_count:usize,validate_count:usize,reject_count:usize,reset_count:usize,guest_entered:bool,guest_instruction_executed:bool,trap_return_executed:bool,hgatp_written:bool,active_stage2:bool};
var obj:FirstInstructionReadinessPlan=undefined; var inited=false; pub fn init(o:vm.VmId,v:vcpu.VcpuId)void{obj=empty(o,v,0);inited=true;} pub fn object()*const FirstInstructionReadinessPlan{return mut();} fn mut()*FirstInstructionReadinessPlan{if(!inited)init(vm.object().id,vcpu.object().id);return &obj;} fn dep(n:[]const u8,b:Blocker)Dependency{return .{.name=n,.present=false,.valid=false,.checksum=0,.blocker=b};} fn empty(o:vm.VmId,v:vcpu.VcpuId,r:usize)FirstInstructionReadinessPlan{return .{.owner_vm_id=o,.owner_vcpu_id=v,.state=.empty,.deps=.{dep("hgatp-candidate",.hgatp_missing),dep("activation-plan",.activation_plan_missing),dep("guest-entry-frame",.entry_frame_missing),dep("trap-return-frame",.trap_return_frame_missing)},.first_blocker=.empty,.blocker_count=1,.next_required_action=.none,.execution_chain_checksum=0,.consumed_hgatp_checksum=0,.consumed_activation_plan_checksum=0,.consumed_guest_entry_frame_checksum=0,.consumed_trap_return_frame_checksum=0,.build_count=0,.validate_count=0,.reject_count=0,.reset_count=r,.guest_entered=false,.guest_instruction_executed=false,.trap_return_executed=false,.hgatp_written=false,.active_stage2=false};} pub fn reset()void{const p=mut();obj=empty(p.owner_vm_id,p.owner_vcpu_id,p.reset_count+1);}
fn mix(a:usize,b:usize)usize{return (a ^% (b+%0xd6e8feb86659fd93))*%0xa5a3564e27f59c9d;} fn calc(p:FirstInstructionReadinessPlan)usize{var x:usize=0x6669703236; inline for(.{p.consumed_hgatp_checksum,p.consumed_activation_plan_checksum,p.consumed_guest_entry_frame_checksum,p.consumed_trap_return_frame_checksum,p.owner_vm_id,p.owner_vcpu_id})|v| x=mix(x,v); return if(x==0)1 else x;} fn next(e:Blocker)Next{return switch(e){.hgatp_missing=>.build_hgatp_candidate,.activation_plan_missing=>.build_activation_plan,.entry_frame_missing=>.build_guest_entry_frame,.trap_return_frame_missing=>.build_trap_return_frame,.none=>.guarded_trap_return_assembly_preparation,else=>.none};}
fn ensure()void{if(hgatp.object().state!=.validated){_=hgatp.build();_=hgatp.validate();} if(sp.object().state!=.validated){_=sp.build();_=sp.validate();} if(gef.object().state!=.validated)_=gef.build(); if(trf.object().state!=.validated)_=trf.build();}
pub fn build()Result{ensure(); const p=mut();p.build_count+=1;p.state=.built;p.owner_vm_id=vm.object().id;p.owner_vcpu_id=vcpu.object().id; p.consumed_hgatp_checksum=hgatp.object().checksum;p.consumed_activation_plan_checksum=sp.object().checksum;p.consumed_guest_entry_frame_checksum=gef.object().checksum;p.consumed_trap_return_frame_checksum=trf.object().checksum; p.deps[0]=.{.name="hgatp-candidate",.present=hgatp.object().state!=.empty,.valid=hgatp.object().state==.validated,.checksum=p.consumed_hgatp_checksum,.blocker=.hgatp_missing}; p.deps[1]=.{.name="activation-plan",.present=sp.object().state!=.empty,.valid=sp.object().state==.validated,.checksum=p.consumed_activation_plan_checksum,.blocker=.activation_plan_missing}; p.deps[2]=.{.name="guest-entry-frame",.present=gef.object().state!=.empty,.valid=gef.object().state==.validated,.checksum=p.consumed_guest_entry_frame_checksum,.blocker=.entry_frame_missing}; p.deps[3]=.{.name="trap-return-frame",.present=trf.object().state!=.empty,.valid=trf.object().state==.validated,.checksum=p.consumed_trap_return_frame_checksum,.blocker=.trap_return_frame_missing}; p.execution_chain_checksum=calc(p.*); return validate();}
fn first()Blocker{const p=object(); if(p.state==.empty)return .empty; if(p.guest_entered)return .guest_entered_forbidden; if(p.guest_instruction_executed)return .instruction_executed_forbidden; if(p.trap_return_executed)return .trap_return_executed_forbidden; if(p.hgatp_written)return .hgatp_written_forbidden; if(p.active_stage2)return .active_stage2_forbidden; for(p.deps)|d| if(!d.present or !d.valid or d.checksum==0)return d.blocker; if(p.execution_chain_checksum==0)return .checksum_zero; return .none;} fn reject(e:Blocker)Result{const p=mut();p.reject_count+=1;p.state=.rejected;p.first_blocker=e;p.blocker_count=1;p.next_required_action=next(e);return .rejected;} pub fn validate()Result{const p=mut();p.validate_count+=1;const e=first();if(e!=.none)return reject(e);p.state=.validated;p.first_blocker=.none;p.blocker_count=0;p.next_required_action=next(.none);return .ok;}
pub fn missingHgatp()Result{reset();return reject(.hgatp_missing);} pub fn missingActivation()Result{reset();return reject(.activation_plan_missing);} pub fn missingEntry()Result{reset();return reject(.entry_frame_missing);} pub fn missingTrap()Result{reset();return reject(.trap_return_frame_missing);} pub fn markGuest()Result{_=build();mut().guest_entered = true;return validate();} pub fn markInstruction()Result{_=build();mut().guest_instruction_executed = true;return validate();} pub fn markTrap()Result{_=build();mut().trap_return_executed = true;return validate();} pub fn markStage2()Result{_=build();mut().active_stage2 = true;return validate();} pub fn markHgatpWritten()Result{_=build();mut().hgatp_written = true;return validate();}
fn bn(e:Blocker)[]const u8{return switch(e){.none=>"none",.empty=>"empty",.hgatp_missing=>"hgatp-missing",.activation_plan_missing=>"activation-plan-missing",.entry_frame_missing=>"entry-frame-missing",.trap_return_frame_missing=>"trap-return-frame-missing",.guest_entered_forbidden=>"guest-entered-forbidden",.instruction_executed_forbidden=>"instruction-executed-forbidden",.trap_return_executed_forbidden=>"trap-return-executed-forbidden",.hgatp_written_forbidden=>"hgatp-written-forbidden",.active_stage2_forbidden=>"active-stage2-forbidden",.checksum_zero=>"checksum-zero"};} fn rn(r:Result)[]const u8{return if(r==.ok)"ok" else "rejected";} fn non()void{uart.write("hv: guest_entered=false\r\nhv: guest_instruction_executed=false\r\nhv: trap_return_executed=false\r\nhv: hgatp_written=false\r\nhv: active_stage2=false\r\n");}
fn summary()void{const p=object();uart.write("hv: first_instruction_plan.state=");uart.write(@tagName(p.state));uart.write("\r\nhv: first_instruction_plan.execution_chain_checksum=");uart.writeHex(p.execution_chain_checksum);uart.write("\r\nhv: first_instruction_plan.consumed_hgatp_checksum=");uart.writeHex(p.consumed_hgatp_checksum);uart.write("\r\nhv: first_instruction_plan.consumed_activation_plan_checksum=");uart.writeHex(p.consumed_activation_plan_checksum);uart.write("\r\nhv: first_instruction_plan.consumed_guest_entry_frame_checksum=");uart.writeHex(p.consumed_guest_entry_frame_checksum);uart.write("\r\nhv: first_instruction_plan.consumed_trap_return_frame_checksum=");uart.writeHex(p.consumed_trap_return_frame_checksum);uart.write("\r\nhv: first_instruction_plan.next_required_action=");uart.write(@tagName(p.next_required_action));uart.write("\r\n");}
pub fn printStatusCommand()void{summary();printBlockersCommand();non();} pub fn printBuildCommand()void{const r=build();uart.write("hv: first_instruction_plan.build_result=");uart.write(rn(r));uart.write("\r\n");summary();non();} pub fn printValidateCommand()void{const r=validate();uart.write("hv: first_instruction_plan.validate_result=");uart.write(rn(r));uart.write("\r\n");summary();printBlockersCommand();non();} pub fn printBlockersCommand()void{uart.write("hv: first_instruction_plan.blocker_count=");uart.writeDec(object().blocker_count);uart.write("\r\nhv: first_instruction_plan.blocker=");uart.write(bn(object().first_blocker));uart.write("\r\n");} pub fn printNextCommand()void{uart.write("hv: first_instruction_plan.next_required_action=");uart.write(@tagName(object().next_required_action));uart.write("\r\n");} pub fn printChainCommand()void{summary();for(object().deps)|d|{uart.write("hv: first_instruction_plan.dependency=");uart.write(d.name);uart.write(" present=");uart.write(if(d.present)"yes" else "no");uart.write(" valid=");uart.write(if(d.valid)"yes" else "no");uart.write(" checksum=");uart.writeHex(d.checksum);uart.write(" blocker=");uart.write(bn(d.blocker));uart.write("\r\n");} non();} pub fn printChecksumCommand()void{uart.write("hv: first_instruction_plan.execution_chain_checksum=");uart.writeHex(object().execution_chain_checksum);uart.write("\r\n");} pub fn printResetCommand()void{reset();uart.write("hv: first_instruction_plan.reset_result=ok\r\n");summary();non();} pub fn printTest(label:[]const u8,r:Result)void{uart.write("hv: first_instruction_plan.");uart.write(label);uart.write("=");uart.write(rn(r));uart.write("\r\n");printBlockersCommand();summary();non();}
